const ICP_DEFINITION = `
Ideal Customer Profile:
- Company size: 20-2000 employees
- Industry: SaaS, e-commerce, or professional services
- Geography: India or United States
- Signals of intent: filled out a demo/contact form (not a newsletter signup)
`;

function buildPrompt(record) {
  const f = record.fields || {};
  return `${ICP_DEFINITION}

Lead to evaluate:
- Company: ${f.Company ?? 'unknown'}
- Company size: ${f['Company Size'] ?? 'unknown'}
- Industry: ${f.Industry ?? 'unknown'}
- Country: ${f.Country ?? 'unknown'}
- Source: ${f.Source ?? 'unknown'}

Return ONLY valid JSON (no markdown fences, no commentary) matching exactly:
{"score": <0-100 integer>, "priority": "<high|medium|low>", "reasoning": "<one sentence>", "persona": "<short label>"}`;
}

async function callOpenAI(prompt, apiKey, strict) {
  const systemMsg = strict
    ? 'You return ONLY raw valid JSON. No markdown code fences. No explanation text.'
    : 'You are a B2B lead qualification assistant. Return valid JSON only.';

  const response = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: systemMsg },
        { role: 'user', content: prompt },
      ],
      temperature: 0.3,
    }),
  });

  if (!response.ok) {
    throw new Error(`OpenAI request failed: ${response.status}`);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content ?? '';
}

function tryParseJson(text) {
  const cleaned = text.replace(/```json|```/g, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch {
    return null;
  }
}

export const code = async (inputs) => {
  const { crmRecord, openaiApiKey } = inputs;
  const prompt = buildPrompt(crmRecord);

  let raw, parsed;
  try {
    raw = await callOpenAI(prompt, openaiApiKey, false);
    parsed = tryParseJson(raw);
    if (!parsed) {
      raw = await callOpenAI(prompt, openaiApiKey, true);
      parsed = tryParseJson(raw);
    }
  } catch (err) {
    // No real API key configured yet — this catch is EXPECTED to fire until one is added.
    return {
      recordId: crmRecord.id,
      apiError: err.message,
      fields: {
        'Lead Score': 0,
        Priority: 'medium',
        'AI Reasoning': `AI scoring unavailable (${err.message}). Defaulted to medium priority for manual review. (Persona: unknown)`,
      },
    };
  }

  if (!parsed) {
    return {
      recordId: crmRecord.id,
      fields: {
        'Lead Score': 0,
        Priority: 'medium',
        'AI Reasoning': 'AI scoring failed to return valid JSON after retry; defaulted for manual review. (Persona: unknown)',
      },
    };
  }

  const score = Number(parsed.score) || 0;
  const priority = ['high', 'medium', 'low'].includes(parsed.priority) ? parsed.priority : 'medium';
  const reasoning = parsed.reasoning ?? '';
  const persona = parsed.persona ?? 'unknown';

  return {
    recordId: crmRecord.id,
    fields: {
      'Lead Score': score,
      Priority: priority,
      'AI Reasoning': `${reasoning} (Persona: ${persona})`,
    },
  };
};
